class Solution {
    private static final int MOD = 1_000_000_007;
    public int countWinningSequences(String s) {
        int n = s.length();
        // dp[i][last][diff] = count of sequences of length i ending with 'last' and having diff = Bob - Alice
        // diff ranges from -n to n, so we shift by n to make it 0..2n
        int[][][] dp = new int[n + 1][3][2 * n + 2];
        // Initialize for i = 0
        for (int last = 0; last < 3; last++) {
            dp[0][last][n] = 1; // diff = 0 shifted by n
        }
        for (int i = 1; i <= n; i++) {
            char alice = s.charAt(i - 1);
            int a = 0;
            if (alice == 'W') a = 1;
            else if (alice == 'E') a = 2;
            for (int prev = 0; prev < 3; prev++) {
                for (int diff = 0; diff <= 2 * n; diff++) {
                    if (dp[i - 1][prev][diff] == 0) continue;
                    for (int curr = 0; curr < 3; curr++) {
                        if (curr == prev) continue;
                        int delta = 0;
                        if (curr == 0 && a == 2) delta = 1;      // Bob F beats Alice E
                        else if (curr == 1 && a == 0) delta = 1; // Bob W beats Alice F
                        else if (curr == 2 && a == 1) delta = 1; // Bob E beats Alice W
                        else if (a == 0 && curr == 2) delta = -1; // Alice F beats Bob E
                        else if (a == 1 && curr == 0) delta = -1; // Alice W beats Bob F
                        else if (a == 2 && curr == 1) delta = -1; // Alice E beats Bob W
                        int newDiff = diff + delta;
                        if (newDiff < 0 || newDiff > 2 * n) continue;
                        dp[i][curr][newDiff] = (dp[i][curr][newDiff] + dp[i - 1][prev][diff]) % MOD;
                    }
                }
            }
        }
        long res = 0;
        for (int last = 0; last < 3; last++) {
            for (int diff = n + 1; diff <= 2 * n; diff++) {
                res = (res + dp[n][last][diff]) % MOD;
            }
        }
        return (int) res;
    }
}
